import{_ as b,o as e,c as a,j as p,a as t,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"烈焰猴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/烈焰猴.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/烈焰猴.md"}'),n={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/烈焰猴.md"};function s(o,r,l,_,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"烈焰猴",tabindex:"-1"},[t("烈焰猴 "),p("a",{class:"header-anchor",href:"#烈焰猴","aria-label":'Permalink to "烈焰猴"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004D")])])],-1),d('<h1 id="烈焰猴-1" tabindex="-1">烈焰猴 <a class="header-anchor" href="#烈焰猴-1" aria-label="Permalink to &quot;烈焰猴&quot;">​</a></h1><p>【小火焰猴】<br> D+500<br> 独立随从</p><p>屁屁的火焰以腹部产生的瓦斯为燃料，即便被雨淋到也不会熄灭，腹部产生的瓦斯在屁屁燃烧着。身体状况不好的话，火焰会变弱。<br> 系别：格斗+火系。</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量4<br> ■敏捷6<br> ■耐力2<br> ▓▓心智属性<br> ■智力4<br> ■感知4<br> ■决心2<br> ▓▓互动属性<br> ■风度2<br> ■操控2<br> ■沉着6</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动3-反射3-投掷3<br> ■求生3-强韧3<br> ■射击1<br> ■武技5-拳5</p><p>▓▓心智系<br> ■学识5-魔法5<br> ■器用1<br> ■手艺1<br> ■专注3-意志3</p><p>▓▓互动系<br> ■洞察3-侦查3<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 3<br> ▓速度 16<br> ▓先攻 12<br> ▓防御 5+1<br> ▓生命值 5<br> ▓意志力池 8<br> ▓意志 12+2<br> ▓反射 14+2<br> ▓强韧 10+2<br> ▓侦查 10+1<br> ▓敏感范围 80米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量/敏捷+武技+拳+天生武器伤害=19+3</p><p>宝可梦技艺近战攻击预设：力量/敏捷+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量/敏捷+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力/感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：<br> 基础防御5+1<br> ▓▓▓▓性别：</p><p>▓▓▓▓特性：<br> 【格斗系宝可梦】：小火焰猴的全身视为3L的天生武器。</p><p>【火系宝可梦】：小火焰猴有着与生俱来对火焰能量的敏感，在使用火系技能时获得3dp火焰能量加值。</p><p>【御三家之名】：小火焰猴作为御三家之一的人气宝可梦，在风度检定时获得3dp的增强加值。</p><p>【生命之炎】：小火焰猴的屁屁上有着长年不熄的火焰，这象征着它旺盛的生命力，即便是在冰天雪地之中也依旧令人感到发自莫名的温暖。小火焰猴拥有5点寒冰能量抗力。</p><p>【铁拳】：小火焰猴的天生武器伤害额外提升3L。小火焰猴使用拳类技能时额外获得1点来自技艺的附加成功。（拳类技能包括：子弹拳，音速拳，吸取拳，爆裂拳，火焰拳，彗星拳，暗影拳，冰冻拳，雷电拳，真气拳，百万吨重拳。）</p><p>【猛火】：小火焰猴在使用火系技能的时候获得额外3dp的火焰能量加值。当小火焰猴的完好生命池低于1/4时，使用火系技能额外获得1点来自火焰能量的附加成功。<br> （铁拳与猛火特性必须在购买小火焰猴时选择一个，仅能选择一个，不可更改。）</p><p>【勇气之路】：与真实的猿猴相似，小火焰猴十分好奇且淘气，但在逼迫之下，小火焰猴可以变得很勇敢。<br> 小火焰猴的反射和强韧豁免+2，意志豁免+4。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓可学习技能：</p><p>火系技能：火花 火焰拳 喷射火焰 闪焰冲锋 大字爆炎 火焰踢 热风</p><p>恶系技能：诡计 挑衅</p><p>电系技能：雷电拳</p><p>冰系技能：冰冻拳</p><p>虫系技能：急速折返</p><p>毒系技能：垃圾射击</p><p>格斗系技能：音速拳 近身战 真气弹 真气拳 快速防守 健美</p><p>超能系技能：冥想 睡觉</p><p>岩石系技能：尖石攻击 岩石封锁 隐形岩</p><p>飞行系技能：燕返 杂技</p><p>一般系技能：击掌奇袭 剑舞 守住 报恩 硬撑 再来一次</p><p>地面系技能：地震</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>————————————————————<br> 【猛火猴】<br> 由小火焰猴支付10xp进化而来<br> 独立随从<br> 猛火猴视为C级召唤物。<br> 猛火猴仅能由小火焰猴进化而来，不可单独购买。</p><p>尾部火焰的大小和蓝色面纹的鲜艳成都决定在群族内地位的高低。能熟练控制尾部火焰的大小，以自己擅长的距离进行战斗。利用天花板和墙壁使出空中攻击。尾部的火焰也是武器之一。</p><p>系别：格斗+火系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量9<br> ■敏捷11<br> ■耐力6<br> ▓▓心智属性<br> ■智力9<br> ■感知9<br> ■决心6<br> ▓▓互动属性<br> ■风度6<br> ■操控6<br> ■沉着11</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动5-投掷5-反射5<br> ■求生5-强韧5<br> ■射击1<br> ■武技8-拳8</p><p>▓▓心智系<br> ■学识8-魔法8<br> ■器用1<br> ■手艺1<br> ■专注5-意志5</p><p>▓▓互动系<br> ■洞察5-侦查5<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 4<br> ▓速度 30米<br> ▓先攻 22<br> ▓防御 10+2<br> ▓生命值 15<br> ▓意志力池 29<br> ▓意志 24+3<br> ▓反射 25+4<br> ▓强韧 20+3<br> ▓侦查 21+3<br> ▓敏感范围 200米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：</p><p>普通攻击：力量/敏捷+武技+拳+天生武器伤害=31+4/30+5</p><p>宝可梦技艺近战攻击预设：力量/敏捷+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量/敏捷+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力/感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御10+2</p><p>▓▓▓▓性别：</p><p>▓▓▓▓特性：</p><p>【提升：勇气之路】：进化成为猛火猴之后，勇气已经不断涌出。猛火猴的强韧反射豁免的增强加值提升至3，意志豁免的增强加值提升至7。</p><p>【提升：铁拳】：猛火猴是小火焰猴中历经各种战斗后脱颖而出的强者，本特性提供的天生武器伤害加值提升至6L，使用拳类技能的附加成功提升至2。</p><p>【提升：猛火】：猛火猴对火焰的感知和控制能力都上升了一个档次，使用火系技能的火焰能量加值提升至6dp，血量低于1/4时获得来自火焰能量的附加成功提升至2。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓可学习技能：</p><p>同小火焰猴。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>———————————————</p><p>【烈焰猴】<br> 由猛火猴支付20xp进化而来<br> 独立随从<br> 烈焰猴视为B级召唤物。<br> 烈焰猴仅能由猛火猴进化而来，不可单独购买。</p><p>性格像头上燃烧的火焰一样激烈。在速度方面无可匹敌。用速度玩弄对手。会使用手脚并用的独特战斗方式。</p><p>系别：格斗+火系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量14<br> ■敏捷16<br> ■耐力11<br> ▓▓心智属性<br> ■智力14<br> ■感知14<br> ■决心11<br> ▓▓互动属性<br> ■风度11<br> ■操控11<br> ■沉着16</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动8-反射8-投掷8<br> ■求生8-强韧8<br> ■射击1<br> ■武技11-拳11</p><p>▓▓心智系<br> ■学识11-魔法11<br> ■器用1<br> ■手艺1<br> ■专注8-意志8</p><p>▓▓互动系<br> ■洞察8-侦查8<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 5<br> ▓速度 （力量【14】+敏捷【16】+体积【5】+每1点敏捷上的附加获得3移动速度）=44米<br> ▓先攻 （敏捷【16】+沉着【16】）=32<br> ▓防御 （敏捷感知的平均值【15】+较高者的附加成功【3】）= 15+3<br> ▓生命值 （耐力【11】+体积【5】+耐力附加【 2】×5）=26<br> ▓意志力池 （决心【11】+沉着【16】+决心附加【2 】×2）=31<br> ▓意志 （决心【11】+专注8+意志【8】）=45+5<br> ▓反射 （敏捷【16】+运动8+反射【8】）=40+6<br> ▓强韧 （耐力【11】+生存8+强韧【8】）=35+5<br> ▓侦查 （感知【14】+洞察8+侦查【8】）=34+5<br> ▓敏感范围 （感知【14】*20米+感知上的附加成功【2 】*20米）=320米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：</p><p>普通攻击预设：力量+武技+拳+天生武器伤害=47+6</p><p>宝可梦技艺近战攻击预设：力量/敏捷+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量/敏捷+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力/感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御15+3</p><p>▓▓▓▓性别：</p><p>▓▓▓▓特性：</p><p>【提升：铁拳】：烈焰猴是整个族群真正的王者，本特性提供的天生武器伤害加值提升至15L。</p><p>【提升：猛火】：烈焰猴才是宝可梦中真正的控火大师，使用火系技能的火焰能量加值提升至15dp。</p><p>【提升：勇气之路】：烈焰猴所具备的勇气不需要任何旁观者来评价，因为只有真正的勇者才配站在它的面前。烈焰猴的强韧反射豁免的增强加值提升至6，意志豁免的增强加值提升至14。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓可学习技能：</p><p>同小火焰猴。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',99)])])}const m=b(n,[["render",s]]);export{f as __pageData,m as default};
